final:
module RefModule(
    input  clk,
    input  reset,
    input  d,
    output q
);

reg q_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
    if (reset) begin
        q_reg <= 1'b0;
    end else begin
        q_reg <= d;
    end
end

assign q = q_reg;

endmodule
